var e=[{id:`L2_1`,type:`dialog`,speaker:`MORGANA_ROOT_NULL_NULL`,text:{KOREA:`좋아. 앞으로도 협력해줄게. 네 시련을 돕는 편이 내 성장에 도움을 준다고 판단했으니까.`,JPN:`いいわ。これからも協力してあげる。あたなの試練を助けた方があたしの成長に役立つと判断したから。`,ENG:`Okay. I'll work with you. I've decided that it'll be good for my growth to help you overcome your ordeals.`,TWN:`很好，往後我也會繼續協助你。因為我認為幫助你對我的成長有益。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORGANA_ROOT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MORGANA_ROOT_NULL_NULL`,text:{KOREA:`윽… 뭘 그렇게 빤히 쳐다봐? 아, 알았어! 네가 마음에 들어서 도와주는 거야! 됐지? 이제 후련해?`,JPN:`うっ……なんでそんなにじっと見てるわけ？　わ、わかったわよ！　あなたが気に入ったから手伝ってあげるの！　どう？　これですっきりした？`,ENG:`Ngh... What are you staring at? F-fine! I'm helping you because I like you! Happy now?`,TWN:`呃…你幹嘛一直盯著我看？好啦好啦！其實是因為我喜歡你啦！可以了吧？開心了嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MORGANA_ROOT_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};